-- ── HeyForm ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hostable conversational form builder for surveys, quizzes, and lead capture forms.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; hosted plans from $15/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HeyForm Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HeyForm review 2026: open-source conversational form builder features, self-hosting, pricing plans, pros and cons, and alternatives like Typeform and Tally.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HeyForm is an open-source, conversational form builder designed to give small businesses an affordable, self-hostable alternative to expensive proprietary form tools like Typeform. It was founded in 2020 by a small founding team who had previously run their own businesses and grew frustrated that existing form builders were either visually outdated, priced out of reach for small companies, or missing features they needed; rather than building a closed commercial product from day one, the founders decided to open-source the core project so developers could inspect, self-host, and contribute to it. That decision paid off quickly: after opening the codebase, HeyForm hit the number-one spot on trending open-source lists for several days and surpassed 6,000 GitHub stars within its first four months, and the repository (hosted at github.com/heyform/heyform) has since grown to roughly 8,700-8,900 stars. The company does not publicly disclose formal headquarters or large-scale funding rounds, consistent with its bootstrapped, community-driven, indie-open-source origin, and it remains a small team. Technically, HeyForm lets users build one-question-at-a-time conversational forms, surveys, quizzes, and polls through a visual editor, with support for conditional logic, custom themes, redirect-on-completion rules, custom metadata fields, and detailed form-level reporting and analytics. Because the core product is open source, teams with technical resources can self-host HeyForm via Docker on their own infrastructure for full data control and zero platform fees beyond hosting costs, while non-technical users can instead use HeyForm's official hosted SaaS version. On the hosted side, HeyForm offers a Free plan with unlimited forms, 250 responses per month, and 50MB of workspace storage; a Basic (hosted) plan at $15/month with 5,000 responses per month and 10GB storage; a Premium plan at $24/month adding 20,000 responses per month, 20GB storage, up to 3 team members, a custom domain, custom CSS, and removal of HeyForm branding; and a Business plan at $40/month adding 150,000 responses per month, 50GB storage, up to 10 team members, unlimited file upload size, priority support, and zero payment-processing commission (versus 3% on Basic and 1% on Premium for forms that collect payments). An Enterprise tier with custom pricing is available for larger organizations, and a 7-day free trial is offered on paid hosted plans. HeyForm's target audience is small businesses, indie makers, startups, and developers who want either a low-cost hosted conversational form tool or full ownership of their form data through self-hosting, avoiding vendor lock-in and the steep per-response pricing common among proprietary competitors. Its principal competitors are Typeform, Tally, Jotform, and Google Forms; HeyForm differentiates primarily through being genuinely open source and self-hostable (which none of Typeform, Tally, or Jotform offer at a comparable level), combined with materially lower pricing on its hosted plans and a payment-commission structure that decreases the more a customer pays, rewarding growth rather than penalizing it. The open-source nature of the project also means HeyForm's roadmap and bug fixes are shaped in part by community contributions on GitHub, which has helped it maintain feature parity with much larger, VC-funded form-builder competitors despite its small team size.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fddc4cea-b640-45b6-a982-077960bcbadc';

