-- ── Hi.Events ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source event ticketing and management platform, a self-hostable alternative to Eventbrite with low-fee cloud hosting.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud from 0.75% + $0.40 per paid ticket$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hi.Events Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hi.Events review 2026: open-source event ticketing features, self-hosted vs cloud pricing, pros and cons, and alternatives like Eventbrite and Ticket Tailor.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hi.Events is an open-source event management and ticket-selling platform positioned as a self-hostable alternative to Eventbrite, Ticket Tailor, Tito, and Dice.fm for organizers who want full control over branding, checkout, attendee data, and infrastructure. The project's codebase is maintained publicly on GitHub under the organization HiEventsDev, licensed under AGPL-3.0 with additional terms, and commercial licensing is also available for organizations that need terms beyond the open-source license. The exact founding date is not publicly documented in detail, though the project's Hacker News 'Show HN' launch post referenced being its second public launch by mid-2024, indicating the platform was in active development for some time before that. Public information does not clearly establish a formal company headquarters or team size, consistent with Hi.Events' origins as a smaller, developer-led open-source project rather than a large venture-backed company; it is described as built by a developer who created it after being unable to find an event ticketing tool that was both flexible and easy to use. Hi.Events is available in two deployment modes: a fully self-hosted, free-to-use version that organizers run on their own servers via Docker, and Hi.Events Cloud, a fully managed hosted version with zero setup, automatic updates, and managed infrastructure for organizers who don't want to run their own servers. On the self-hosted side, there are no platform fees at all beyond standard payment processor fees (roughly Stripe's 2.9% + 30 cents in the US), giving organizers the full ticket face value minus only payment processing costs. On the Cloud side, Hi.Events charges a platform fee of just 0.75% plus $0.40 per paid ticket sold, which is dramatically lower than the typical 3-7% fees charged by competitors like Eventbrite; free events remain completely free to host and list regardless of deployment mode, and organizers can choose to pass ticket fees on to buyers or absorb them from their own revenue. Functionally, Hi.Events covers the core needs of running ticketed events: configurable ticket types and pricing tiers, promo codes and discounts, capacity and seating management, an event check-in app supporting offline QR-code scanning, embeddable ticket-widget checkout for organizer websites, customizable branded event pages, attendee messaging tools, instant payouts via Stripe Connect, multi-currency and tax/fee configuration, reporting and analytics dashboards, team roles and permissions, and an API for custom integrations. This makes it suitable for a wide range of event types, from nightclub and concert ticketing to conferences, workshops, and festivals. Hi.Events' target audience includes independent event organizers, nightlife and concert promoters, conference and workshop hosts, and developers or agencies who want to self-host ticketing infrastructure for clients rather than depend on a third-party SaaS platform with high fees and limited data ownership. Its primary competitors are Eventbrite, Ticket Tailor, Tito, and Dice.fm; Hi.Events differentiates itself primarily through being fully open source and self-hostable, which none of those closed-source competitors offer, combined with substantially lower platform fees on its managed Cloud offering and full white-label branding control for organizers who want the checkout experience to feel entirely native to their own website rather than redirecting to a third-party ticketing domain.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b';

