INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Cloud VPS tiers$q$, $q$CX, CPX, CCX, and CAX server families cover cost-optimized shared vCPU, AMD EPYC, dedicated vCPU, and ARM-based Ampere instances.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Dedicated root servers$q$, $q$Auction-based and configurable bare-metal servers for workloads needing full hardware control.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$API, CLI and IaC support$q$, $q$Full REST API and CLI with first-party Terraform, Ansible, Packer, and Kubernetes Cloud Controller Manager integrations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Storage products$q$, $q$S3-compatible Object Storage, Storage Box (network file storage), and Nextcloud-based Storage Share.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Networking$q$, $q$Private Networks, Load Balancers, and free DNS management for building multi-server architectures.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Security and compliance$q$, $q$Free stateful firewalls, DDoS protection, GDPR-aligned EU hosting, and ISO/IEC 27001-certified data centers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$One-click apps$q$, $q$Pre-configured installs for Docker, WordPress, Nextcloud, GitLab, Grafana, and more, deployable in minutes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Global data centers$q$, $q$Owned facilities in Germany, Finland, the United States, and Singapore for lower-latency regional deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Significantly cheaper than AWS, Azure, and Google Cloud for comparable compute$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$All-inclusive pricing with no extra charges for bandwidth, IPv4/IPv6, or DDoS protection$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Strong infrastructure-as-code support via Terraform, Ansible, and Kubernetes tooling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$EU data residency and ISO/IEC 27001 certification appeal to privacy-conscious organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Simple, well-documented API and console for fast provisioning$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Multiple price increases through 2026 have narrowed the cost advantage on some server lines$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Fewer managed services (databases, AI, serverless) compared to AWS or Google Cloud$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Support is primarily ticket and email based rather than 24/7 live chat for lower tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Smaller global data center footprint than the major hyperscalers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Account verification and fraud checks can delay onboarding for some new customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$What is Hetzner used for$q$, $q$Hetzner provides cloud VPS instances, dedicated bare-metal servers, and storage products used to host websites, applications, databases, and Kubernetes clusters at lower cost than major hyperscalers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Is Hetzner cheaper than AWS$q$, $q$Yes, for comparable compute Hetzner is generally several times cheaper than AWS, Azure, or Google Cloud, even after the price increases Hetzner implemented in 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Where are Hetzner's data centers located$q$, $q$Hetzner operates owned data centers in Nuremberg and Falkenstein, Germany, Tuusula, Finland, Ashburn, Virginia and Oregon in the United States, and Singapore.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Does Hetzner offer managed Kubernetes$q$, $q$Hetzner provides a Cloud Controller Manager and integrations that support running Kubernetes on its cloud servers, along with strong Terraform and Ansible tooling for cluster provisioning.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Is Hetzner GDPR compliant$q$, $q$Yes, Hetzner's German and Finnish data centers are GDPR-aligned and ISO/IEC 27001 certified, making it a common choice for EU-based data residency requirements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Who owns Hetzner$q$, $q$Hetzner Online GmbH is privately owned and controlled by founder Martin Hetzner, and it has never taken outside venture capital or private equity funding.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Startup and SaaS hosting$q$, $q$Early-stage companies run production applications, databases, and staging environments on Hetzner Cloud to control infrastructure costs while scaling.$q$, $q$Startups and SaaS teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Self-hosted app deployment$q$, $q$Developers and small teams use one-click apps and Storage Box to self-host tools like Nextcloud, GitLab, and WordPress instead of paying for SaaS subscriptions.$q$, $q$Developers and self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$EU data residency workloads$q$, $q$Organizations with GDPR or data sovereignty requirements host regulated workloads in Hetzner's German and Finnish data centers.$q$, $q$EU-focused businesses and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Cloud CX (Cost-Optimized)$q$, $q$From EUR 5.49/month$q$, $q$monthly$q$, NULL, $q$["Shared vCPU","Included bandwidth","Free firewall","Snapshots and backups available"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Cloud CPX/CCX (Performance/Dedicated)$q$, $q$EUR 20-140/month$q$, $q$monthly$q$, NULL, $q$["AMD EPYC or dedicated vCPU","Higher RAM and NVMe storage","Private networking","Load balancer compatible"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$High-Memory CCX$q$, $q$EUR 275-1040+/month$q$, $q$monthly$q$, NULL, $q$["Dedicated vCPU","High RAM configurations","Suited for databases and memory-intensive apps"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Dedicated Root Servers$q$, $q$Custom / auction pricing$q$, $q$monthly$q$, NULL, $q$["Bare-metal hardware","Auction and fixed configurations","Managed via Hetzner Robot console"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hetzner is a German hosting and cloud infrastructure company that has grown from a small regional web host founded in 1997 into one of Europe's most widely used providers of dedicated servers, cloud VPS instances, and storage products. Unlike most large cloud providers, Hetzner is privately owned and has never taken outside venture or private-equity funding, which has allowed it to keep its pricing structure simple and aggressively low relative to AWS, Google Cloud, and Azure.$q$, $q$The company's infrastructure is anchored in owned data center parks in Nuremberg and Falkenstein, Germany, and Tuusula, Finland, with newer US locations in Ashburn, Virginia and Oregon, and a Singapore data center added in 2024 to serve Asia-Pacific customers. This owned-hardware model, rather than reselling capacity from a third party, is a core part of how Hetzner keeps per-server costs low while maintaining GDPR-aligned EU data residency and ISO/IEC 27001 certification.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hetzner Cloud spans several server families: CX (cost-optimized shared vCPU), CPX (AMD EPYC shared vCPU), CCX (dedicated vCPU for production workloads), and CAX (ARM-based Ampere instances) for energy-efficient, price-competitive compute. Around these compute products sit Load Balancers, private Networks, S3-compatible Object Storage, Storage Box and Storage Share for file-level storage, and free DNS management, giving teams most of what they need to run a full application stack without leaving the platform.$q$, $q$Everything is manageable through the Hetzner Cloud Console, a REST API, and an official CLI, with strong first-party tooling support for Terraform, Ansible, Packer, and Kubernetes via a dedicated Cloud Controller Manager, which makes Hetzner popular for infrastructure-as-code workflows. One-click app installs (Docker, WordPress, Nextcloud, GitLab, Grafana, and others) simplify common deployments, while free stateful firewalls, DDoS protection, and all-inclusive bandwidth pricing round out the security and cost story.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hetzner uses transparent, pay-as-you-go pricing with no separate charges for bandwidth, IPv4/IPv6, DDoS protection, or firewalling. Entry-level cloud instances start around EUR 5.49/month, scaling through mid-tier CPX and CCX instances (roughly EUR 20 to EUR 140/month) up to large dedicated-vCPU and high-memory configurations that can exceed EUR 1,000/month, alongside separately priced dedicated (bare-metal) root servers available through auction or fixed configuration.$q$, $q$Hetzner implemented multiple price increases in 2026, including an adjustment of up to roughly 37% in April and a further round in June that significantly raised prices on the dedicated-vCPU CCX line, which the company attributed to rising hardware and data center costs. Even with these increases, independent comparisons continue to place Hetzner well below AWS, Azure, and Google Cloud for comparable compute, which remains its primary value proposition for cost-conscious developers and startups.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
