INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$No-code funnel builder$q$, $q$Drag-and-drop editor with 40+ interactive elements and conversion-optimized templates for multi-step lead funnels.$q$, 0);
