INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Native ad integrations$q$, $q$Direct connections to Meta and Google Ads for improved ad-to-funnel conversion tracking.$q$, 3);
