INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Built-in A/B testing$q$, $q$Native split testing on higher tiers to optimize flow structure and copy for conversion rate.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Custom code and branding$q$, $q$Custom CSS and code injection plus branding removal for fully white-labeled flows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Calculators and product finders$q$, $q$Interactive pricing calculators and guided product-finder flows for e-commerce and services.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Multi-step funnel approach converts better than static forms for paid acquisition$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Strong lead-quality tools with phone and OTP validation built in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Large template and integration library for fast setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Native Meta and Google Ads integrations aid tracking and optimization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$GDPR-conscious, EU-based provider popular with DACH and European marketers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Pricing scales with response volume, which can get expensive for high-traffic campaigns$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Branding removal and A/B testing are gated behind higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Free plan is limited to only 10 responses per month$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Smaller global brand recognition compared to Typeform or Unbounce$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Advanced features like custom code require Scale or Enterprise tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$What is Heyflow used for$q$, $q$Heyflow is used to build no-code, multi-step lead-generation funnels, quizzes, calculators, and forms that convert better than static landing page forms for paid marketing campaigns.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Does Heyflow have a free plan$q$, $q$Yes, Heyflow offers a free plan that includes up to 10 responses per month, suitable for testing before upgrading to a paid tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$How much does Heyflow cost$q$, $q$Heyflow's paid plans start at $22/month for Starter (50 responses, 5 flows), rising to $79/month for Growth and $229/month for Scale, with custom Enterprise pricing available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Who founded Heyflow$q$, $q$Heyflow was founded in 2020 in Hamburg, Germany by Dustin Jaacks and Amir Bohnenkamp.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Does Heyflow integrate with CRMs$q$, $q$Yes, Heyflow offers more than 50 native integrations including HubSpot, Salesforce, Pipedrive, Google Sheets, and Calendly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Is Heyflow GDPR compliant$q$, $q$Heyflow is based in Germany and built with GDPR compliance in mind, making it a common choice for European businesses with strict data privacy requirements.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$B2B lead generation$q$, $q$Sales and marketing teams build multi-step qualification funnels that route higher-intent leads to sales while filtering out fake submissions.$q$, $q$B2B marketing and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Real estate and financial services$q$, $q$Agencies build mortgage calculators, property finders, and insurance quote flows that personalize pricing based on user input.$q$, $q$Real estate agents and financial advisors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Performance marketing campaigns$q$, $q$Paid acquisition teams replace static landing page forms with interactive funnels connected directly to Meta and Google Ads.$q$, $q$Performance marketers and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["10 responses/month","Basic flow builder","Limited integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Starter$q$, $q$$22/month$q$, $q$monthly$q$, NULL, $q$["50 responses/month","5 flows","Website embedding","Basic integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Growth$q$, $q$$79/month$q$, $q$monthly$q$, NULL, $q$["250 responses/month","10 flows","Calculators","Phone validation","Branding removal"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$Scale$q$, $q$$229/month$q$, $q$monthly$q$, NULL, $q$["1,000 responses/month","20 flows","Native A/B testing","Custom code","Salesforce integration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Heyflow is a no-code platform for building interactive, multi-step lead-generation funnels rather than static one-page forms. Founded in Hamburg in 2020 by Dustin Jaacks and Amir Bohnenkamp, the company built its product around the observation that conversational, personalized funnels convert significantly better for paid acquisition campaigns than traditional landing pages with flat forms.$q$, $q$Since raising a $6 million seed round in 2021 and a $16 million Series A roughly two years later, Heyflow has expanded from its Hamburg headquarters to a second Berlin office and grown its customer base to more than 3,000 marketing teams, primarily in Europe, who use the platform to run lead-gen campaigns for real estate, financial services, insurance, B2B, and e-commerce.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Heyflow provides a drag-and-drop builder with more than 40 interactive elements and conversion-optimized templates, letting non-technical marketers assemble multi-step flows with sliders, calculators, multiple-choice questions, and file uploads. Advanced conditional logic personalizes the path each visitor takes, adapting later questions, pricing, or offers based on earlier responses.$q$, $q$Lead-quality tools such as phone validation and OTP verification help filter out fake or low-intent submissions before they reach a sales team, while native integrations with Meta and Google Ads, plus 50+ CRM and marketing tool integrations (HubSpot, Salesforce, Pipedrive, Google Sheets, Calendly), connect Heyflow directly into existing acquisition and sales workflows. Built-in A/B testing and analytics let teams iterate on funnel performance without needing a developer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Heyflow prices around monthly response quotas rather than flat feature tiers. The Free plan allows up to 10 responses per month for testing; Starter at $22/month includes 50 responses and 5 flows; Growth at $79/month raises this to 250 responses, 10 flows, calculators, phone validation, and branding removal; and Scale at $229/month supports 1,000 responses, 20 flows, native A/B testing, custom code, and Salesforce integration.$q$, $q$Enterprise pricing is custom and adds dedicated support and enhanced security for larger organizations. Teams that outgrow their quota mid-cycle can buy flexible add-on bundles for extra responses or additional flows rather than jumping a full tier, which keeps costs closely tied to actual usage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69056d48-f2a0-4191-ac9b-4a5b7c1c0412', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
