INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Conversational form builder$q$, $q$One-question-at-a-time forms, surveys, quizzes, and polls designed for higher completion rates than traditional forms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Open-source and self-hostable$q$, $q$Full source code available on GitHub, deployable via Docker for teams that want complete data ownership.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Conditional logic$q$, $q$Branching logic that shows or hides questions based on previous answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Custom branding$q$, $q$Custom domains, custom CSS, and branding removal available on Premium and Business plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Team collaboration$q$, $q$Multi-member workspaces with role support on Premium and Business tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Payment collection$q$, $q$Built-in payment forms with a commission rate that decreases as customers move up plan tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Form analytics$q$, $q$Built-in reporting and response metadata for tracking form performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Unlimited forms on every plan$q$, $q$All plans, including Free, allow unlimited forms and questions, with only response volume capped.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Genuinely open source and self-hostable, unlike most form-builder competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Free plan and hosted pricing are significantly cheaper than Typeform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Payment commission decreases as customers scale, rewarding growth$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Active GitHub community contributing features and fixes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Simple, focused feature set that is easy to learn quickly$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Small team behind the hosted product means slower feature releases than larger competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Free plan response cap (250/month) is low for growing businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Self-hosting requires technical setup and ongoing server maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Fewer native integrations than more established form tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Limited public information on company structure, funding, or headquarters$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Is HeyForm free to use$q$, $q$Yes, HeyForm offers a free hosted plan with unlimited forms and 250 responses per month, plus a fully free self-hosted option since the project is open source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Can HeyForm be self-hosted$q$, $q$Yes, HeyForm is open source and can be self-hosted via Docker on your own infrastructure for full control over form data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$How much does HeyForm's hosted plan cost$q$, $q$HeyForm's hosted Basic plan starts at $15/month for 5,000 responses, with Premium at $24/month and Business at $40/month for higher response and storage limits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Does HeyForm charge fees on payment forms$q$, $q$Yes, payment-collecting forms are charged a commission that decreases with plan tier, from 3% on Basic down to 0% on the Business plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Who created HeyForm$q$, $q$HeyForm was created in 2020 by a small founding team frustrated with existing form builders, who later open-sourced the project to the developer community.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$What is HeyForm best used for$q$, $q$HeyForm is best used for conversational surveys, quizzes, polls, and lead-capture forms by small businesses and developers who want an affordable or self-hosted alternative to Typeform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Small business lead capture$q$, $q$Small businesses use HeyForm's hosted plans to build affordable, branded lead and contact forms without paying enterprise form-builder prices.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Self-hosted internal forms$q$, $q$Development teams self-host HeyForm to run internal surveys and data collection tools with full control over hosting and data residency.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Customer feedback and quizzes$q$, $q$Marketing teams build conversational quizzes and feedback surveys to increase completion rates over static forms.$q$, $q$Marketing and customer success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Unlimited forms","250 responses/month","50MB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Basic$q$, $q$$15/month$q$, $q$monthly$q$, NULL, $q$["5,000 responses/month","10GB storage","3% payment commission"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Premium$q$, $q$$24/month$q$, $q$monthly$q$, NULL, $q$["20,000 responses/month","20GB storage","Up to 3 team members","Custom domain and CSS","Branding removal"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$Business$q$, $q$$40/month$q$, $q$monthly$q$, NULL, $q$["150,000 responses/month","50GB storage","Up to 10 team members","0% payment commission","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HeyForm is an open-source conversational form builder created in 2020 by a small team of founders who had run their own businesses and were dissatisfied with the form tools on the market, which they found either outdated, overpriced for small businesses, or missing needed functionality. Rather than launch as another closed SaaS product, the team open-sourced HeyForm's codebase, which quickly gained traction, topping open-source trending lists and passing 6,000 GitHub stars within four months of release.$q$, $q$Today HeyForm is available both as a self-hostable open-source project (via Docker, hosted on GitHub) for teams that want full data ownership, and as an official low-cost hosted SaaS product for teams that prefer a managed service. This dual model lets HeyForm serve both budget-conscious developers who want to run their own infrastructure and small businesses that just want a working conversational form tool without the overhead of proprietary competitors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HeyForm supports one-question-at-a-time conversational forms, surveys, quizzes, and polls, with a visual builder, conditional logic, custom themes, and redirect-on-completion rules. Forms can capture custom metadata and generate built-in reporting so teams can analyze response data without exporting to a separate analytics tool.$q$, $q$Higher hosted tiers unlock a custom domain, custom CSS, HeyForm branding removal, multiple team members, and larger storage and response quotas, while payment-collecting forms benefit from a commission structure that drops from 3% on the entry hosted plan to 0% on the Business plan. Because the project is open source, self-hosters get the same core feature set without response caps, subject only to their own server capacity.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fddc4cea-b640-45b6-a982-077960bcbadc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HeyForm's Free plan includes unlimited forms, 250 responses per month, and 50MB of storage at no cost. The hosted Basic plan is $15/month for 5,000 responses and 10GB storage, Premium is $24/month for 20,000 responses, 20GB storage, 3 team members, and branding removal, and Business is $40/month for 150,000 responses, 50GB storage, 10 team members, and zero payment commission.$q$, $q$Because HeyForm is open source, cost-sensitive teams with technical resources can bypass hosted pricing entirely by self-hosting the platform on their own servers, paying only for their own infrastructure. A custom Enterprise plan and a 7-day free trial on paid tiers round out the pricing structure for larger or trial-first customers.$q$]::text[], 2);
