INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$AI avatar generation$q$, $q$Create realistic talking avatars from stock options or custom photo/video uploads, with Avatar IV delivering consistent likeness across angles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Video translation and dubbing$q$, $q$Translate videos into 175+ languages with lip-sync and preserved voice tone via the Video Translation API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Video Agent$q$, $q$Prompt-to-video automation that writes the script, selects avatar and voice, and renders the finished video.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Text-to-speech (Starfish)$q$, $q$In-house TTS model generating natural-sounding narration accessible via API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Interactive avatars$q$, $q$Real-time conversational AI avatars for live interactions and virtual assistants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Developer API and MCP$q$, $q$Direct API access plus an MCP server and Skills for integrating HeyGen into AI assistants and coding agents.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Template API$q$, $q$Brand-controlled video templates for scaling personalized video production across a team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Proofread API$q$, $q$Automated script and content review before video generation to catch errors early.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Fast turnaround from script to finished video without filming$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Strong translation and lip-sync quality across 175+ languages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Deep developer API, MCP, and coding-agent integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Rapid revenue growth and enterprise adoption signal platform maturity$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Flexible pricing from free tier to pay-as-you-go API access$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Credit system can make real costs higher than the advertised plan price$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Premium avatar features like Avatar IV consume credits quickly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Free plan is limited to only 3 videos per month$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Business and Enterprise pricing requires per-seat costs on top of base fee$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$AI avatars can still show artifacts in complex scenes or fast movement$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$What is HeyGen used for$q$, $q$HeyGen is used to generate AI avatar videos from text scripts for marketing, training, sales, and localization, without needing cameras, actors, or video editors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Who founded HeyGen$q$, $q$HeyGen was founded in 2020 by Joshua Xu, a former Snap engineer, along with co-founder Wayne Liang; the company was originally named Movio before rebranding to HeyGen.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$How much does HeyGen cost$q$, $q$HeyGen offers a free plan with 3 videos per month, a Creator plan at $29/month, Pro plans from $49/month, and a Business plan starting at $149/month plus $20 per additional seat.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Does HeyGen support video translation$q$, $q$Yes, HeyGen's Video Translation API supports over 175 languages and dialects with high lip-sync accuracy while preserving the original speaker's voice and tone.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Is there a HeyGen API for developers$q$, $q$Yes, HeyGen offers six core APIs covering video generation, translation, text-to-speech, and more, plus pay-as-you-go API pricing starting from $5 and an MCP server for AI assistant integration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$How much funding has HeyGen raised$q$, $q$HeyGen has raised approximately $74.6 million across three funding rounds, including a $60 million round in June 2024 led by Benchmark that valued the company at $500 million.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Marketing and localization$q$, $q$Marketing teams translate and dub video content into dozens of languages while preserving the original speaker's voice and delivery.$q$, $q$Marketing and localization teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Corporate training and HR$q$, $q$HR and L&D teams produce consistent training and onboarding videos using AI avatars instead of re-filming with live presenters.$q$, $q$HR and corporate training teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Developer-embedded video generation$q$, $q$Software companies integrate HeyGen's API into their own products to offer AI video generation as a built-in feature.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["3 videos/month","Limited premium feature access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Creator$q$, $q$$29/month ($24/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited videos","200 monthly credits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Pro$q$, $q$From $49/month$q$, $q$monthly$q$, NULL, $q$["1,000 to 100,000 monthly credits","Scalable tiers up to $4,300/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$Business$q$, $q$$149/month + $20/seat$q$, $q$monthly$q$, NULL, $q$["Team collaboration","Brand controls","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HeyGen is an AI video generation company that converts written scripts into realistic talking-avatar videos, eliminating the need for cameras, actors, or video production crews. Founded in 2020 by Joshua Xu, a former Snap engineer, and co-founder Wayne Liang, the company (originally called Movio, briefly Surreal) rebranded to HeyGen and established its headquarters in Los Angeles in 2022, with additional offices in San Francisco, Palo Alto, and Toronto.$q$, $q$HeyGen has grown explosively since 2023, scaling annual recurring revenue from about $1 million to roughly $100 million by late 2025 and surpassing 85,000 paying customers, including large enterprise names like OpenAI, HubSpot, and Ogilvy. A $60 million Series B round in June 2024, led by Benchmark, valued the company at $500 million, reflecting strong investor confidence in the AI video generation category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HeyGen's core product lets users generate videos from custom or stock AI avatars, using 'Avatar IV' technology for consistent likeness across angles and expressions. The Video Translation API supports 175+ languages with high lip-sync accuracy, dubbing videos while preserving the original speaker's voice, tone, and pacing, which is heavily used for localizing marketing, training, and educational content.$q$, $q$The Video Agent feature automates the entire creation process from a single prompt, writing the script, selecting the avatar and voice, and rendering the final video. Developers can integrate HeyGen directly via its six core APIs (Video Generation, Video Agent, Template, Video Translation, Proofread, and Text-to-Speech), or connect through an MCP server for AI assistants like Claude and Skills for coding agents such as Claude Code and Cursor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b433c3e5-1372-4d99-8fbd-7702d9586534', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HeyGen offers a Free plan with up to 3 videos per month and limited access to premium features. The Creator plan is $29/month (or $24/month billed annually) with unlimited videos and 200 credits, while Pro tiers scale from $49/month (1,000 credits) up to $4,300/month (100,000 credits) for high-volume users.$q$, $q$The Business plan starts at $149/month for the first seat plus $20/month per additional seat, and Enterprise pricing is custom for large organizations. Developers can also use a separate pay-as-you-go API pricing track starting from $5, with additional Generative Credit Packs available for usage beyond a plan's monthly allotment.$q$]::text[], 2);
