INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Self-hosted or managed cloud$q$, $q$Deploy Hi.Events on your own servers via Docker for free, or use the fully managed Hi.Events Cloud with zero setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Branded checkout$q$, $q$Embeddable ticket widgets and fully branded event pages keep the buying experience on the organizer's own site.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Offline check-in app$q$, $q$QR-code-based check-in that works offline for venues with unreliable internet connectivity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Flexible ticketing$q$, $q$Configurable ticket types, pricing tiers, capacity limits, and promo codes for varied event formats.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Instant payouts$q$, $q$Stripe Connect integration for direct, fast payouts to organizers rather than delayed platform disbursements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Reporting and analytics$q$, $q$Built-in dashboards for tracking sales, attendance, and revenue across events.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Team roles and permissions$q$, $q$Multi-user access controls for teams managing events collaboratively.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Open API$q$, $q$API access for custom integrations and embedding ticketing into other systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Fully open source and self-hostable, giving organizers complete data ownership$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Cloud platform fees (0.75% + $0.40/ticket) are far lower than Eventbrite and similar platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Free events cost nothing to host in either deployment mode$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Fully branded, white-label checkout experience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Offline QR check-in works well for venues with poor connectivity$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Self-hosting requires technical setup and ongoing server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Smaller team and community support compared to established ticketing platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Less brand recognition and buyer trust than Eventbrite for large public events$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Limited public information on company structure and long-term roadmap$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Fewer built-in marketing and discovery features than larger ticketing marketplaces$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Is Hi.Events really free to use$q$, $q$Yes, the self-hosted version of Hi.Events is completely free with no platform fees, aside from standard payment processing fees on paid tickets.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$What does Hi.Events Cloud cost$q$, $q$Hi.Events Cloud charges a low platform fee of 0.75% plus $0.40 per paid ticket sold, which can be absorbed by the organizer or passed on to buyers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Can Hi.Events be self-hosted$q$, $q$Yes, Hi.Events is open source and can be self-hosted via Docker on your own infrastructure for full control over data and zero platform fees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$What events is Hi.Events used for$q$, $q$Hi.Events is used for concerts, nightclub events, festivals, conferences, and workshops, essentially anywhere organizers need to sell tickets online.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$How does Hi.Events compare to Eventbrite$q$, $q$Hi.Events offers open-source self-hosting and much lower platform fees on its Cloud version than Eventbrite, along with fully branded, white-label checkout instead of a third-party ticketing domain.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Does Hi.Events support offline check-in$q$, $q$Yes, Hi.Events includes a check-in app with offline QR-code scanning support for venues with unreliable internet access.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Independent event organizers$q$, $q$Organizers running concerts, club nights, and festivals use Hi.Events Cloud for low-fee, branded ticketing without building their own infrastructure.$q$, $q$Independent event organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Self-hosted ticketing for agencies$q$, $q$Agencies and developers deploy self-hosted Hi.Events for clients who need full data ownership and no per-ticket platform fees.$q$, $q$Developers and event agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Conferences and workshops$q$, $q$Conference organizers use ticket tiers, promo codes, and check-in tools to manage registration and on-site attendance.$q$, $q$Conference and workshop organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Self-Hosted$q$, $q$Free$q$, $q$one-time setup, self-managed$q$, NULL, $q$["No platform fees","Full source code access","Only payment processor fees apply","Unlimited events"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$Hi.Events Cloud$q$, $q$0.75% + $0.40 per paid ticket$q$, $q$per-ticket$q$, NULL, $q$["Fully managed hosting","Automatic updates","Free for free events","Instant payouts via Stripe Connect"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hi.Events is an open-source event management and ticketing platform built as a self-hostable alternative to closed-source ticketing services like Eventbrite, Ticket Tailor, and Tito. Its code is publicly maintained on GitHub under an AGPL-3.0 license with additional terms, with commercial licensing available for organizations that need it, giving organizers full transparency into how the platform handles checkout, attendee data, and payment processing.$q$, $q$The platform is offered in two forms: a free, fully self-hosted deployment that organizers run on their own infrastructure via Docker with zero platform fees, and Hi.Events Cloud, a fully managed hosted version for organizers who prefer not to run their own servers. This dual model lets Hi.Events serve both technically capable organizers who prioritize data ownership and low fees, and less technical organizers who want a managed SaaS experience with dramatically lower platform fees than incumbents.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hi.Events covers the core functionality needed to run ticketed events, including configurable ticket types and pricing tiers, promo codes, capacity management, and a check-in app that supports offline QR-code scanning for venues with unreliable connectivity. Organizer-branded event pages and embeddable ticket widgets let events be sold directly from an organizer's own website rather than a third-party ticketing domain.$q$, $q$Additional functionality includes attendee messaging, instant payouts through Stripe Connect, multi-currency and tax configuration, reporting and analytics dashboards, team roles and permissions for multi-person event teams, and an API for custom integrations, covering the operational needs of everything from nightlife events and concerts to conferences and workshops.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db2a5c35-cb6d-4682-ad3f-0c3ddff2ba7b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosted Hi.Events is free to use with no platform fees at all; organizers only pay standard payment processing fees (roughly Stripe's 2.9% + 30 cents in the US) on paid ticket sales, and free events cost nothing to host in either deployment mode.$q$, $q$Hi.Events Cloud, the fully managed hosted version, charges a low platform fee of 0.75% plus $0.40 per paid ticket, which organizers can either absorb or pass on to ticket buyers at checkout. This fee structure is substantially lower than the 3-7% typically charged by incumbent ticketing platforms like Eventbrite.$q$]::text[], 2);
