INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Core HR and org management$q$, $q$Centralized employee records, org charts, onboarding workflows, and time-off management.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Performance management$q$, $q$Structured reviews, calibration tools, and continuous feedback to support fair, consistent evaluations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Compensation management$q$, $q$Centralized pay bands, equity tracking, and company-wide compensation consistency tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Native payroll (US and UK)$q$, $q$In-house payroll processing with filing across all 50 US states, plus native UK payroll.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Global Payroll Hub$q$, $q$Connects HR data to local and global payroll partners for countries outside the US and UK.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$People analytics$q$, $q$Dashboards and AI-powered insights surfacing burnout, disengagement, and attrition risk signals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Engagement surveys$q$, $q$AI-powered surveys measuring team and company-wide sentiment over time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$100+ integrations$q$, $q$Connects to ATS, finance, communication, and productivity tools across the HR tech stack.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Modern, design-forward interface compared to legacy enterprise HR systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Modular pricing lets companies pay only for the modules they need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Native payroll in the US and UK with a global hub for other countries$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Strong people analytics and AI-driven engagement tools built into the core platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Well suited for distributed, international mid-market teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Pricing is not published and requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Implementation fees add meaningfully to first-year cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Payroll outside the US and UK depends on third-party partners rather than native processing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Can be costly for very small companies compared to lighter HR tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Some advanced modules require additional cost beyond core HR$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$What is HiBob used for$q$, $q$HiBob's Bob platform is used for core HR administration, payroll, performance management, compensation, and people analytics, primarily by mid-market companies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$How much does HiBob cost$q$, $q$HiBob does not publish fixed pricing; it typically ranges from about $8 to $25 per employee per month depending on modules selected, plus an implementation fee of roughly 10-20% of annual cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Where is HiBob headquartered$q$, $q$HiBob is headquartered in London, United Kingdom, with additional offices including New York and Amsterdam, and was originally founded in Tel Aviv in 2015.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Does HiBob handle payroll$q$, $q$Yes, HiBob offers native payroll processing for the US (all 50 states) and UK, and uses a Payroll Hub to connect to local and global payroll partners for other countries.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Who are HiBob's main competitors$q$, $q$HiBob's main competitors include Rippling, Gusto, BambooHR, Personio, and Workday.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Is HiBob suitable for small businesses$q$, $q$HiBob is primarily designed for mid-market companies rather than very small businesses, and its per-employee pricing and implementation fees can be relatively costly for small teams.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Mid-market HR consolidation$q$, $q$Growing companies replace multiple disconnected HR tools with a single platform covering core HR, performance, and compensation.$q$, $q$HR leaders at mid-market companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Distributed and global teams$q$, $q$Companies with employees across multiple countries use Bob's Payroll Hub and global HR data model to manage a distributed workforce centrally.$q$, $q$People teams managing global workforces$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Performance and compensation cycles$q$, $q$HR teams run structured performance review cycles with calibration and connect outcomes directly to compensation planning.$q$, $q$HR and compensation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Core HR$q$, $q$From approximately $8/employee/month$q$, $q$monthly (custom quote)$q$, NULL, $q$["Employee records","Onboarding","Org charts","Time off management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Essential$q$, $q$Approximately $16/employee/month$q$, $q$monthly (custom quote)$q$, NULL, $q$["Core HR features","Performance management","Engagement surveys"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$Full Suite$q$, $q$Up to approximately $25/employee/month$q$, $q$monthly (custom quote)$q$, NULL, $q$["Payroll","Compensation management","People analytics","Workforce planning"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HiBob is a cloud HR technology company founded in 2015 in Tel Aviv that builds Bob, a modern human capital management platform aimed at mid-market employers. The company has grown into a globally distributed business headquartered in London, backed by roughly $574 million in venture funding across eight rounds, with a 2023 valuation of nearly $2.7 billion following a $150 million Series D round from investors including Fidelity Management, Bessemer Venture Partners, and Battery Ventures.$q$, $q$Bob is designed to stand apart from older, utilitarian enterprise HR software through a distinctly modern, design-forward user interface, while still covering the full employee lifecycle from onboarding through offboarding. It serves thousands of mid-market customers globally, particularly companies with distributed or international teams that want a single connected system for HR, payroll, and people analytics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bob's core platform covers HR administration, onboarding, time and attendance, time-off management, and org charts, layered with performance management tools including structured reviews, calibration for fairness across teams, and continuous feedback. AI-powered engagement surveys capture team and company sentiment, while people analytics highlights risk signals such as burnout or attrition before they become retention problems.$q$, $q$On compensation, Bob offers centralized management of pay bands and company-wide compensation consistency, connected to workforce planning tools. For payroll, HiBob runs native, in-house payroll for the US (all 50 states) and UK, and uses a 'Payroll Hub' to connect HR data to local and global payroll partners for other countries, letting distributed teams run global payroll without a patchwork of disconnected systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HiBob does not publish fixed list pricing; instead, pricing is quoted per employee per month (PEPM) based on headcount, selected modules, and contract length. Industry estimates place core HR pricing around $8 per employee per month, with fuller module bundles, including performance, compensation, and time and attendance, ranging roughly from $16 to $25 per employee per month.$q$, $q$Customers typically also pay a one-time implementation fee equal to roughly 10-20% of their annual software cost to cover onboarding and data migration. Because pricing is customized, prospective customers need to request a quote and demo directly from HiBob's sales team to get an exact figure for their organization.$q$, $q$$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('113b6907-6942-4e86-a060-16d7decf6a9f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
