INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f6d6eb38-8f44-43cb-b351-fe77b22730dd', $q$Unified dashboard$q$, $q$Session replay, errors, logs, and traces surfaced together instead of across separate tools.$q$, 6);
