INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f6d6eb38-8f44-43cb-b351-fe77b22730dd', $q$Combines session replay, error monitoring, logging, and tracing in one open-source product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f6d6eb38-8f44-43cb-b351-fe77b22730dd', $q$Self-hostable at no licensing cost for teams wanting full data control$q$, 1);
